const body = $input.first().json.body;

const pusher = body.pusher.name;
const repo = body.repository.name;
const branch = body.ref.replace("refs/heads/", "");
const commits = body.commits;

const commitList = commits.map((c, i) => 
  `${i + 1}. ${c.message} — by ${c.author.name}`
).join("<br>");

const message = `
<h3>🔔 New GitHub Activity!</h3>
<b>Repository:</b> ${repo}<br>
<b>Branch:</b> ${branch}<br>
<b>Pushed by:</b> ${pusher}<br><br>
<b>Commits:</b><br>
${commitList}
`;

return [{ json: { message, repo, branch, pusher } }];
